mapper.select:
SELECT dept_id, dept_name, manager_id, created_at
FROM   department
WHERE  dept_id = #{deptId}

mapper.update:
UPDATE department
SET dept_name  = #{deptName},
    manager_id = #{managerId, jdbcType=VARCHAR}
WHERE dept_id = #{deptId}

mapper.select:
SELECT COUNT(*) FROM department
WHERE dept_name = #{deptName}

    AND dept_id != #{deptId}

